function createBaseCAppOverviewChange(): CAppOverviewChange {
  return { appOverview: [], removedAppid: [], fullUpdate: false, updateComplete: false };
}

export const CAppOverviewChange: MessageFns<CAppOverviewChange> = {
  encode(message: CAppOverviewChange, writer: BinaryWriter = new BinaryWriter()): BinaryWriter {
    for (const v of message.appOverview) {
      CAppOverview.encode(v!, writer.uint32(10).fork()).join();
    }
    for (const v of message.removedAppid) {
      writer.uint32(16).uint32(v!);
    }
    if (message.fullUpdate !== undefined && message.fullUpdate !== false) {
      writer.uint32(24).bool(message.fullUpdate);
    }
    if (message.updateComplete !== undefined && message.updateComplete !== false) {
      writer.uint32(32).bool(message.updateComplete);
    }
    return writer;
  },

  decode(input: BinaryReader | Uint8Array, length?: number): CAppOverviewChange {
    const reader = input instanceof BinaryReader ? input : new BinaryReader(input);
    const end = length === undefined ? reader.len : reader.pos + length;
    const message = createBaseCAppOverviewChange();
    while (reader.pos < end) {
      const tag = reader.uint32();
      switch (tag >>> 3) {
        case 1: {
          if (tag !== 10) {
            break;
          }

          message.appOverview.push(CAppOverview.decode(reader, reader.uint32()));
          continue;
        }
        case 2: {
          if (tag === 16) {
            message.removedAppid.push(reader.uint32());

            continue;
          }

          if (tag === 18) {
            const end2 = reader.uint32() + reader.pos;
            while (reader.pos < end2) {
              message.removedAppid.push(reader.uint32());
            }

            continue;
          }

          break;
        }
        case 3: {
          if (tag !== 24) {
            break;
          }

          message.fullUpdate = reader.bool();
          continue;
        }
        case 4: {
          if (tag !== 32) {
            break;
          }

          message.updateComplete = reader.bool();
          continue;
        }
      }
      if ((tag & 7) === 4 || tag === 0) {
        break;
      }
      reader.skip(tag & 7);
    }
    return message;
  },
};

function longToNumber(int64: { toString(): string }): number {
  const num = globalThis.Number(int64.toString());
  if (num > globalThis.Number.MAX_SAFE_INTEGER) {
    throw new globalThis.Error("Value is larger than Number.MAX_SAFE_INTEGER");
  }
  if (num < globalThis.Number.MIN_SAFE_INTEGER) {
    throw new globalThis.Error("Value is smaller than Number.MIN_SAFE_INTEGER");
  }
  return num;
}

interface MessageFns<T> {
  encode(message: T, writer?: BinaryWriter): BinaryWriter;
  decode(input: BinaryReader | Uint8Array, length?: number): T;
}
